1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	  cursed?: boolean;
14	  enchantment?: number;
15	}
16	
17	const CURSE_RATE = 0.5;
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_RATE = 0.3;
20	
21	interface QuoteStep {
22	  op: "quote";
23	  items: Item[];
24	}
25	
26	interface Scenario {
27	  customer: { yearsWithMHPCO: number };
28	  steps: QuoteStep[];
29	}
30	
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	const COMPONENT_BASE = 25;
33	const BLOCK_SIZE = 3;
34	const BLOCK_BASE = 60;
35	
36	const componentBase = (count: number): number =>
37	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
38	
39	const unitBase = (type: string): number =>
40	  COMPONENT_TYPES.has(type) ? COMPONENT_BASE : (BASE_PREMIUMS[type] ?? 0);
41	
42	const baseForType = (type: string, count: number): number =>
43	  COMPONENT_TYPES.has(type)
44	    ? componentBase(count)
45	    : unitBase(type) * count;
46	
47	const countByType = (items: Item[]): Map<string, number> =>
48	  items.reduce(
49	    (counts, item) =>
50	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
51	    new Map<string, number>(),
52	  );
53	
54	const baseForItems = (items: Item[]): number =>
55	  [...countByType(items)].reduce(
56	    (total, [type, count]) => total + baseForType(type, count),
57	    0,
58	  );
59	
60	const itemBase = (item: Item): number => unitBase(item.type);
61	
62	const isHighlyEnchanted = (item: Item): boolean =>
63	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
64	
65	const itemSurcharges = (item: Item): number => {
66	  const base = itemBase(item);
67	  const rules: { applies: boolean; rate: number }[] = [
68	    { applies: item.cursed ?? false, rate: CURSE_RATE },
69	    { applies: isHighlyEnchanted(item), rate: HIGH_ENCHANTMENT_RATE },
70	  ];
71	  return rules
72	    .filter((rule) => rule.applies)
73	    .reduce((sum, rule) => sum + rule.rate * base, 0);
74	};
75	
76	const priceQuote = (items: Item[]): { premium: number } => {
77	  const policyBase = baseForItems(items);
78	  const surcharges = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
79	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
80	  const premium = Math.ceil(
81	    policyBase + surcharges + firstInsuranceSurcharge + PROCESSING_FEE,
82	  );
83	  return { premium };
84	};
85	
86	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
87	  const results = scenario.steps.map((step) => priceQuote(step.items));
88	  return { results };
89	};
